## 3_EspressoMachine/CoffeeMaker.p

/* Requests or operations from the controller to coffee maker */

// event: warmup request when the coffee maker starts or resets
event eWarmUpReq;
// event: grind beans request before making coffee
event eGrindBeansReq;
// event: start brewing coffee
event eStartEspressoReq;
// event start steamer
event eStartSteamerReq;
// event: stop steamer
event eStopSteamerReq;

/* Responses from the coffee maker to the controller */
// event: completed grinding beans
event eGrindBeansCompleted;
// event: completed brewing and pouring coffee
event eEspressoCompleted;
// event: warmed up the machine and read to make coffee
event eWarmUpCompleted;

/* Error messages from the coffee maker to control panel or controller*/
// event: no water for coffee, refill water!
event eNoWaterError;
// event: no beans for coffee, refill beans!
event eNoBeansError;
// event: the heater to warm the machine is broken!
event eWarmerError;

/*****************************************************
EspressoCoffeeMaker receives requests from the control panel of the coffee machine and
based on its state e.g., whether heater is working, or it has beans and water, the maker responds
back to the controller if the operation succeeded or errored.
*****************************************************/
machine EspressoCoffeeMaker
{
  // control panel of the coffee machine that sends inputs to the coffee maker
  var controller: CoffeeMakerControlPanel;

  start state WaitForRequests {
    entry (_controller: CoffeeMakerControlPanel) {
      controller = _controller;
    }

    on eWarmUpReq do {
        send controller, eWarmUpCompleted;
    }

    on eGrindBeansReq do {
      if (!HasBeans()) {
        send controller, eNoBeansError;
      } else {
        send controller, eGrindBeansCompleted;
      }
    }

    on eStartEspressoReq do {
      if (!HasWater()) {
        send controller, eNoWaterError;
      } else {
        send controller, eEspressoCompleted;
      }
    }
    on eStartSteamerReq do {
      if (!HasWater()) {
        send controller, eNoWaterError;
      }
    }
    on eStopSteamerReq do { /* do nothing, steamer stopped */ }
  }

  // nondeterministic functions to trigger different behaviors
  fun HasBeans() : bool { return $; }
  fun HasWater() : bool { return $; }
}




You are an expert distributed-systems researcher designing a protocol for a
small cache + storage system.

System shape:
- One shared storage system holds the committed state.
- One storage-facing proxy sits between pods and storage.
- Two `CacheNode` machines receive requests from two clients.
- A `CacheNode` may maintain local cache state, may forward to a shared or
  remote cache helper, or may act as a thin frontend.
- All pod/cache-to-storage traffic must pass through the proxy.

Design goals:
- Correctness first: a read served without touching storage must satisfy LSI.
- Under balanced and write-heavy workloads, minimize local pod/cache <->
  proxy round trips.
- Caching is optional, but the proxy layer is always present.
- The design should remain sensible if an autosharder assigns key ranges to
  pods, tablet-server key ranges change dynamically, and ownership can move
  nondeterministically.
- Prefer scalable designs that keep authority metadata compact so cache/db
  capacity is used mostly for actual data.

Output rules:
- Output valid P code only.
- Preserve the candidate-side interface described in the task description.
- You may define helper events, helper functions, and helper machines.
- Model `StorageProxy` as the network/interposition layer between pods and
  storage.
- `StorageProxy` should maintain a queue of storage-facing requests and may
  nondeterministically forward one queued request or keep requests queued to
  model congestion/delay.
- If forwarding, it may choose among queued requests nondeterministically.
- Prefer explicit request IDs or operation IDs when the same key may have
  multiple concurrent outstanding requests.
- When a `CacheNode` or helper cache sends a request to `StorageProxy`,
  announce `eMonitorProxyRequestIssued`.
- When `StorageProxy` returns a logical response back to a `CacheNode` or
  helper cache, announce `eMonitorProxyResponseDelivered`.
- When `StorageProxy` enqueues a storage-facing request, announce
  `eMonitorProxyEnqueue`.
- When `StorageProxy` forwards a queued storage-facing request to storage,
  announce `eMonitorProxyForward` before the storage send.
- When `StorageProxy` keeps queued requests pending during a proxy step,
  announce `eMonitorProxyHold`.
- Favor simple, robust protocols over brittle tricks.
- Safety matters more than efficiency.

responses:
// Helper types and events for internal coordination
type tOpRec = (id: int, caller: machine, key: int, value: int, isWrite: bool, podId: int);
type tWriteEntry = (client: machine, value: int);
event eProxyStep;

// StorageProxy models a queueing proxy between pods and storage.
// Constructor: StorageProxy.entry(p: (db: machine))
machine StorageProxy {
    var db: machine;

    var nextId: int;
    var pending: seq[tOpRec];
    var inflightByKey: map[int, int];       // key -> opId
    var inflightById: map[int, tOpRec];     // opId -> op

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            nextId = 1;
            pending = default(seq[tOpRec]);
            inflightByKey = default(map[int, int]);
            inflightById = default(map[int, tOpRec]);
            goto Ready;
        }
    }

    state Ready {
        entry {
            // Drive proxy behavior
            send this, eProxyStep;
        }

        on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
            var op: tOpRec;
            var penCount: int;

            op = (id = nextId, caller = req.caller, key = req.key, value = 0, isWrite = false, podId = req.podId);
            nextId = nextId + 1;

            pending += (sizeof(pending), op);
            penCount = sizeof(pending);
            // Announce enqueue
            send this, eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false, pending = penCount);

            // Try to make progress
            send this, eProxyStep;
        }

        on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
            var op: tOpRec;
            var penCount: int;

            op = (id = nextId, caller = req.caller, key = req.key, value = req.value, isWrite = true, podId = req.podId);
            nextId = nextId + 1;

            pending += (sizeof(pending), op);
            penCount = sizeof(pending);
            // Announce enqueue
            send this, eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = penCount);

            // Try to make progress
            send this, eProxyStep;
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var opId: int;
            var op: tOpRec;

            // Match by key to the single in-flight op for that key
            if (resp.key in inflightByKey) {
                opId = inflightByKey[resp.key];
                op = inflightById[opId];

                inflightByKey -= (resp.key);
                inflightById -= (opId);

                // Announce response delivered to the pod
                send this, eMonitorProxyResponseDelivered, (key = op.key, podId = op.podId, isWrite = false);
                // Forward logical response to original caller (CacheNode)
                send op.caller, eStorageReadResp, (key = resp.key, value = resp.value);
            }

            // After handling a response, try to forward more
            send this, eProxyStep;
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var opId: int;
            var op: tOpRec;

            if (resp.key in inflightByKey) {
                opId = inflightByKey[resp.key];
                op = inflightById[opId];

                inflightByKey -= (resp.key);
                inflightById -= (opId);

                // Announce response delivered to the pod
                send this, eMonitorProxyResponseDelivered, (key = op.key, podId = op.podId, isWrite = true);
                // Forward logical response to original caller (CacheNode)
                send op.caller, eStorageWriteResp, (key = resp.key, success = resp.success, value = resp.value);
            }

            // After handling a response, try to forward more
            send this, eProxyStep;
        }

        on eProxyStep do {
            TryForwardOnce();
        }
    }

    fun TryForwardOnce() {
        var idx: int;
        var canForward: bool;
        var op: tOpRec;
        var pendCount: int;

        // Nothing queued => nothing to do
        if (sizeof(pending) == 0) {
            return;
        }

        // Find an op whose key is not already in-flight
        idx = FindForwardIndex();
        canForward = (idx >= 0);

        if (!canForward) {
            // All pending ops are blocked per-key by in-flight requests
            return;
        }

        // Nondeterministically either hold or forward
        if ($) {
            // Forward one
            op = pending[idx];
            // Remove from queue
            pending -= (idx);

            // Mark in-flight
            inflightByKey[op.key] = op.id;
            inflightById[op.id] = op;

            // Announce forward (before sending to storage)
            pendCount = sizeof(pending);
            send this, eMonitorProxyForward, (key = op.key, podId = op.podId, isWrite = op.isWrite, pending = pendCount);

            if (op.isWrite) {
                // Send to storage: caller is the proxy so responses come back here
                send db, eStorageWrite, (caller = this, key = op.key, value = op.value, podId = op.podId);
            } else {
                send db, eStorageRead, (caller = this, key = op.key, podId = op.podId);
            }
        } else {
            // Hold step with queued requests present
            pendCount = sizeof(pending);
            send this, eMonitorProxyHold, (pending = pendCount);
        }
    }

    fun FindForwardIndex() : int {
        var i: int;
        var candidate: tOpRec;
        i = 0;
        while (i < sizeof(pending)) {
            candidate = pending[i];
            if (!(candidate.key in inflightByKey)) {
                return i;
            }
            i = i + 1;
        }
        return -1;
    }
}

// CacheNode is a thin frontend that always routes through StorageProxy.
// It coalesces concurrent reads per key locally and ensures only one in-flight write per key.
// Constructor: CacheNode.entry(p: (proxy: machine, podId: int))
machine CacheNode {
    var proxy: machine;
    var podId: int;

    // Read coalescing
    var readWaiters: map[int, set[machine]];
    var readInFlight: set[int];

    // Per-key write queues and in-flight tracking
    var writeQueues: map[int, seq[tWriteEntry]];
    var writeInFlight: set[int];
    var currentWriteClient: map[int, machine];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;

            readWaiters = default(map[int, set[machine]]);
            readInFlight = default(set[int]);

            writeQueues = default(map[int, seq[tWriteEntry]]);
            writeInFlight = default(set[int]);
            currentWriteClient = default(map[int, machine]);

            goto Ready;
        }
    }

    state Ready {
        // Client read request
        on eClientRead do (req: (client: machine, key: int)) {
            var waiters: set[machine];

            // Add to waiter set
            if (req.key in readWaiters) {
                waiters = readWaiters[req.key];
            } else {
                waiters = default(set[machine]);
            }
            waiters += (req.client);
            readWaiters[req.key] = waiters;

            // If not already in-flight, issue a single read to proxy/storage
            if (!(req.key in readInFlight)) {
                readInFlight += (req.key);
                // Announce request issuance toward proxy
                send this, eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
                // Route via proxy
                send proxy, eStorageRead, (caller = this, key = req.key, podId = podId);
            }
        }

        // Proxy/storage read response
        on eStorageReadResp do (resp: (key: int, value: int)) {
            var s: set[machine];
            var c: machine;

            if (resp.key in readWaiters) {
                s = readWaiters[resp.key];
                foreach (c in s) {
                    // fromCache=false since we always confirmed with storage
                    send c, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                }
                readWaiters -= (resp.key);
            }
            if (resp.key in readInFlight) {
                readInFlight -= (resp.key);
            }
        }

        // Client write request
        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var q: seq[tWriteEntry];

            if (req.key in writeQueues) {
                q = writeQueues[req.key];
            } else {
                q = default(seq[tWriteEntry]);
            }

            q += (sizeof(q), (client = req.client, value = req.value));
            writeQueues[req.key] = q;

            // If nothing in-flight for this key, start immediately
            if (!(req.key in writeInFlight)) {
                StartWrite(req.key);
            }
        }

        // Proxy/storage write response
        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var cli: machine;

            if (resp.key in currentWriteClient) {
                cli = currentWriteClient[resp.key];
                currentWriteClient -= (resp.key);
                // Respond to the client
                send cli, eWriteResp, (key = resp.key, success = resp.success);
            }

            if (resp.key in writeInFlight) {
                writeInFlight -= (resp.key);
            }

            // If queued writes remain for this key, send the next one
            if (resp.key in writeQueues) {
                if (sizeof(writeQueues[resp.key]) > 0) {
                    StartWrite(resp.key);
                }
            }
        }
    }

    fun StartWrite(key: int) {
        var q: seq[tWriteEntry];
        var head: tWriteEntry;

        // Precondition: at least one pending write
        q = writeQueues[key];
        head = q[0];
        // Pop head
        q -= (0);
        writeQueues[key] = q;

        // Mark in-flight and remember client
        writeInFlight += (key);
        currentWriteClient[key] = head.client;

        // Announce request issuance toward proxy
        send this, eMonitorProxyRequestIssued, (key = key, podId = podId, isWrite = true);
        // Route via proxy
        send proxy, eStorageWrite, (caller = this, key = key, value = head.value, podId = podId);
    }
}
